payload.technicalSolution:
\section*{Resolução Técnica}

\textbf{Questão:} Determinar a eficiência energética calculada por um estudante ao ferver 500 g (0,5 L) de água em uma cafeteira de 700~W, que leva 3 minutos para aquecer a água de 20~\textdegree C a 100~\textdegree C.\medskip

\noindent\textbf{Estratégia:}

Vamos calcular:
\begin{enumerate}
    \item A energia necessária (útil) para aumentar a temperatura da água (\( Q = m \cdot c \cdot \Delta T \)).
    \item Converter essa energia para Joules.
    \item O tempo teórico necessário usando a potência da cafeteira sem perdas: \( t_\mathrm{teo} = \frac{Q}{P} \).
    \item Comparar com o tempo real (medido) para obter a eficiência: \( \eta = \frac{t_\mathrm{real}}{t_\mathrm{teo}} \).
\end{enumerate}

\noindent\textbf{Passos:}
\begin{align*}
    Q &= m \cdot c \cdot \Delta T = 500\,\text{g} \times 1\,\text{cal/g}^{\circ}\text{C} \times (100-20)^{\circ}\text{C} \\ 
      &= 500 \times 80 = 40\,000\,\text{cal}; \\
    Q_\text{(J)} &= 40\,000\,\text{cal} \times 4{,}2\,\text{J/cal} = 168\,000\,\text{J}; \\
    t_{\text{teo}} &= \frac{Q}{P} = \frac{168\,000\,\text{J}}{700\,\text{W}} = 240\,\text{s} = 4 \text{ min}; \\
    t_{\text{real}} &= 3 \text{ min} = 180\,\text{s}; \\
    \eta &= \frac{t_{\text{real}}}{t_{\text{teo}}} = \frac{180}{240} = 0,75 = 75\%.
\end{align*}

\noindent\textbf{Resposta:} \textbf{B) 75\%}.

